<?php
namespace App\Services\Admin;
use App\Models\{Agent,AgentRouteAssignment,AgentSeatAllocation,AgentWalletTransaction,TravelSchedule}; use Illuminate\Support\Facades\DB;
class AgentService { public function save(array $data, ?Agent $agent=null): Agent { return DB::transaction(function() use($data,$agent){ $agent=$agent ?? new Agent(); $agent->fill($data); $agent->save(); app(ActivityLogger::class)->log('agent.saved','Agent saved',$agent); return $agent; }); } public function assignRoute(array $data): AgentRouteAssignment { $assignment=AgentRouteAssignment::updateOrCreate(['agent_id'=>$data['agent_id'],'travel_route_id'=>$data['travel_route_id']],$data); app(ActivityLogger::class)->log('agent.route_assigned','Agent route assignment saved',$assignment); return $assignment; } public function allocateSeats(array $data): AgentSeatAllocation { $schedule=TravelSchedule::with('seatLayout.seats')->findOrFail($data['travel_schedule_id']); $assignment=AgentRouteAssignment::where('agent_id',$data['agent_id'])->where('travel_route_id',$schedule->travel_route_id)->where('status','active')->firstOrFail(); if($data['allocated_seats']>$assignment->seat_quota) abort(422,'Allocation exceeds route seat quota.'); $allocation=AgentSeatAllocation::updateOrCreate(['agent_id'=>$data['agent_id'],'travel_schedule_id'=>$data['travel_schedule_id']],$data+['allocation_date'=>$schedule->departure_at->toDateString()]); app(ActivityLogger::class)->log('agent.seats_allocated','Agent seat allocation saved',$allocation); return $allocation; } public function credit(Agent $agent,float $amount,string $description='',?int $userId=null): AgentWalletTransaction { return DB::transaction(function() use($agent,$amount,$description,$userId){ $agent->lockForUpdate(); $agent->increment('credit_balance',$amount); $agent->refresh(); return AgentWalletTransaction::create(['agent_id'=>$agent->id,'type'=>'credit','amount'=>$amount,'balance_after'=>$agent->credit_balance,'description'=>$description,'created_by'=>$userId]); }); } public function debit(Agent $agent,float $amount,string $description='',?int $userId=null,?int $bookingId=null): AgentWalletTransaction { return DB::transaction(function() use($agent,$amount,$description,$userId,$bookingId){ $agent=Agent::lockForUpdate()->findOrFail($agent->id); if($agent->credit_balance < $amount) abort(422,'Insufficient agent credit.'); $agent->decrement('credit_balance',$amount); $agent->refresh(); return AgentWalletTransaction::create(['agent_id'=>$agent->id,'booking_id'=>$bookingId,'type'=>'debit','amount'=>$amount,'balance_after'=>$agent->credit_balance,'description'=>$description,'created_by'=>$userId]); }); } public function validateBooking(Agent $agent, TravelSchedule $schedule, int $seatCount, float $total): void { $assignment=AgentRouteAssignment::where('agent_id',$agent->id)->where('travel_route_id',$schedule->travel_route_id)->where('status','active')->first(); if(!$assignment) abort(422,'Agent is not assigned to this route.'); if($agent->credit_balance < $total) abort(422,'Insufficient agent credit.'); $allocation=AgentSeatAllocation::where('agent_id',$agent->id)->where('travel_schedule_id',$schedule->id)->where('status','active')->first(); if(!$allocation || $allocation->used_seats + $seatCount > $allocation->allocated_seats) abort(422,'Agent seat allocation limit exceeded.'); $dailyUsed=$agent->bookings()->whereDate('travel_date',$schedule->departure_at->toDateString())->sum(DB::raw('(select count(*) from booking_seat where booking_seat.booking_id = bookings.id)')); if($assignment->daily_limit && $dailyUsed + $seatCount > $assignment->daily_limit) abort(422,'Agent daily booking limit exceeded.'); } public function consumeAllocation(Agent $agent, TravelSchedule $schedule, int $seatCount): void { AgentSeatAllocation::where('agent_id',$agent->id)->where('travel_schedule_id',$schedule->id)->increment('used_seats',$seatCount); } }
